const fs = require('fs');
// ── Machine configuration ──────────────────────────────────────────────────────────────────────────────
// Edit config.json to change paths for your machine. Do not edit this node.
const CONFIG_PATH = process.env.TAROT_CONFIG || 'D:/TarotCardProject/config.json';
// ─────────────────────────────────────────────────────────────────────────────────
const config = JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf8'));

return [{ json: {
    // Machine-specific (from config.json)
    SpreadsheetPath: config.SpreadsheetPath,
    CardsDir:        config.DefaultDeckDir + '/Cards',
    // Workflow-specific
    SheetName: 'Character Prompts',
} }];

const { execFileSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const params = $input.first().json;
const spreadsheetPath = params.SpreadsheetPath;
const cardsDir = params.CardsDir;
const sheetName = params.SheetName;

// --- Read ODS spreadsheet via xlsx (bundled with n8n) ---
let rows;
try {
  const XLSX = require('xlsx');
  const wb = XLSX.readFile(spreadsheetPath);
  if (!wb.Sheets[sheetName]) {
    throw new Error(
      `Sheet "${sheetName}" not found. Available sheets: ${wb.SheetNames.join(', ')}`
    );
  }
  rows = XLSX.utils.sheet_to_json(wb.Sheets[sheetName], { defval: '' });
  console.log(`[Read Spreadsheet] Read ${rows.length} rows via xlsx`);
} catch (xlsxErr) {
  // Fallback: read via Python + odfpy
  console.warn('[Read Spreadsheet] xlsx failed (' + xlsxErr.message + '), falling back to Python');
  const pyScript = `
import json, sys
try:
    from odf.opendocument import load
    from odf.table import Table, TableRow, TableCell
    from odf.text import P
except ImportError:
    import subprocess
    subprocess.check_call([sys.executable, '-m', 'pip', 'install', 'odfpy', '-q'])
    from odf.opendocument import load
    from odf.table import Table, TableRow, TableCell
    from odf.text import P

def cell_value(c):
    repeat = int(c.getAttribute('numbercolumnsrepeated') or 1)
    ps = c.getElementsByType(P)
    val = str(ps[0]) if ps else ''
    return [val] * repeat

doc = load(sys.argv[1])
for sheet in doc.spreadsheet.getElementsByType(Table):
    if sheet.getAttribute('name') != sys.argv[2]:
        continue
    rows_out = []
    headers = None
    for row in sheet.getElementsByType(TableRow):
        vals = []
        for c in row.getElementsByType(TableCell):
            vals.extend(cell_value(c))
        while vals and not vals[-1]:
            vals.pop()
        if not vals:
            continue
        if headers is None:
            headers = vals
        else:
            d = {headers[i]: vals[i] if i < len(vals) else '' for i in range(len(headers))}
            rows_out.append(d)
    print(json.dumps(rows_out))
    break
`;
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'n8n-ods-'));
  const tmpPy = path.join(tmpDir, '_n8n_read_ods.py');
  fs.writeFileSync(tmpPy, pyScript, 'utf8');
  const raw = execFileSync(
    'python3', [tmpPy, spreadsheetPath, sheetName],
    { encoding: 'utf8', maxBuffer: 20 * 1024 * 1024 }
  );
  rows = JSON.parse(raw.trim());
  console.log(`[Read Spreadsheet] Read ${rows.length} rows via Python`);
}

if (!rows || rows.length === 0) {
  throw new Error(
    `[Read Spreadsheet] No rows found in sheet "${sheetName}". ` +
    `Check that SpreadsheetPath and SheetName are correct.`
  );
}

// --- Validate required columns ---
const required = ['Card', 'Character Name', 'ComfyUI Positive Prompt', 'ComfyUI Negative Prompt'];
const firstRow = rows[0];
const missing = required.filter(c => !(c in firstRow));
if (missing.length > 0) {
  throw new Error(
    `[Read Spreadsheet] Missing columns: ${missing.join(', ')}. ` +
    `Found: ${Object.keys(firstRow).join(', ')}`
  );
}

// --- Group rows by Card ---
const byCard = {};
for (const row of rows) {
  const rawCard = (row['Card'] || '').trim();
  if (!rawCard) continue;
  // Skip repeat header rows (Card column literally contains 'Card')
  if (rawCard === 'Card') continue;
  // Strip trailing orientation suffix ONLY for known orientations: "Queen of Pentacles (upright)" -> "Queen of Pentacles"
  // Leave other qualifiers like "Influencer (modern)" intact -> "Influencer_(modern).json"
  const card = rawCard.replace(/\s*\((upright|reversed|between)\)\s*$/i, '').trim();
  if (!card) continue;
  if (!byCard[card]) byCard[card] = [];
  byCard[card].push(row);
}

const cardNames = Object.keys(byCard);
console.log(`[Read Spreadsheet] ${cardNames.length} unique cards, ${rows.length} rows total`);

return cardNames.map(cardName => ({
  json: {
    CardName: cardName,
    Rows: byCard[cardName],
    CardsDir: cardsDir
  }
}));

const fs = require('fs');
const path = require('path');

const allItems = $input.all().map(i => i.json);
const results = [];
const errors = [];

for (const item of allItems) {
  const cardName = item.CardName;
  const rows = item.Rows;
  const cardsDir = item.CardsDir;

  // Form filename: replace spaces (and any forward/backslashes) with underscores
  const filename = cardName.replace(/[ \/\\]+/g, '_') + '.json';
  const jsonPath = path.resolve(cardsDir, filename);
  if (!jsonPath.startsWith(path.resolve(cardsDir))) throw new Error('Path traversal detected: ' + filename);

  if (!fs.existsSync(jsonPath)) {
    errors.push({
      card: cardName,
      file: filename,
      error: 'File not found'
    });
    console.warn(`[Update Cards] File not found: ${jsonPath}`);
    continue;
  }

  let cardData;
  try {
    cardData = JSON.parse(fs.readFileSync(jsonPath, 'utf8'));
  } catch (e) {
    errors.push({ card: cardName, file: filename, error: 'JSON parse error: ' + e.message });
    console.warn(`[Update Cards] Parse error in ${filename}: ${e.message}`);
    continue;
  }

  const cardMeta = cardData['data.Cards'];
  if (!cardMeta || !Array.isArray(cardMeta.records)) {
    errors.push({ card: cardName, file: filename, error: 'No data.Cards.records array in JSON' });
    console.warn(`[Update Cards] No records in ${filename}`);
    continue;
  }

  let updatedCount = 0;
  const updateLog = [];

  for (const row of rows) {
    const charNameFull = (row['Character Name'] || '').trim();
    const posPrompt    = (row['ComfyUI Positive Prompt'] || '').trim();
    const negPrompt    = (row['ComfyUI Negative Prompt'] || '').trim();

    // Extract orientation from between the last pair of parentheses: "Odysseus (upright)" → "upright"
    const orientMatch = charNameFull.match(/\(([^)]+)\)\s*$/);
    if (!orientMatch) {
      console.warn(`[Update Cards] Cannot parse orientation from: "${charNameFull}" (card: ${cardName})`);
      updateLog.push({ orientation: '(unknown)', status: 'skipped - no parentheses' });
      continue;
    }
    const orientation = orientMatch[1].trim();

    // Extract character name without the orientation suffix
    const charName = charNameFull.replace(/\s*\([^)]+\)\s*$/, '').trim();

    // Find the matching record
    const record = cardMeta.records.find(r => r.Orientation === orientation);
    if (!record) {
      console.warn(
        `[Update Cards] No record with Orientation="${orientation}" in ${filename}. ` +
        `Available: ${cardMeta.records.map(r => r.Orientation).join(', ')}`
      );
      updateLog.push({ orientation, status: 'skipped - orientation not found in JSON' });
      continue;
    }

    // Ensure Prompts section exists
    if (!record.Prompts) record.Prompts = {};

    // Write CharacterImage prompts into the record
    record.Prompts.CharacterImage = {
      CharacterName: charName,
      Positive:      posPrompt,
      Negative:      negPrompt
    };

    updatedCount++;
    updateLog.push({ orientation, charName, status: 'updated' });
  }

  // Write updated JSON back
  try {
    fs.writeFileSync(jsonPath, JSON.stringify(cardData, null, 2), 'utf8');
    results.push({
      card: cardName,
      file: filename,
      updated: updatedCount,
      log: updateLog
    });
    console.log(`[Update Cards] ${cardName}: ${updatedCount}/${rows.length} orientations updated`);
  } catch (e) {
    errors.push({ card: cardName, file: filename, error: 'Write error: ' + e.message });
    console.warn(`[Update Cards] Write error for ${filename}: ${e.message}`);
  }
}

if (results.length === 0 && errors.length > 0) {
  throw new Error(
    `[Update Cards] All ${errors.length} cards failed. First error: ` +
    `${errors[0].card} — ${errors[0].error}`
  );
}

if (errors.length > 0) {
  console.warn(`[Update Cards] ${errors.length} cards had errors (${results.length} succeeded)`);
}

return [...results, ...errors].map(r => ({ json: r }));

const all = $input.all().map(i => i.json);
const succeeded = all.filter(j => !j.error);
const failed    = all.filter(j =>  j.error);

const totalUpdated = succeeded.reduce((s, j) => s + (j.updated || 0), 0);

console.log(
  `[Report] Done: ${succeeded.length} cards updated (${totalUpdated} records), ` +
  `${failed.length} errors`
);

if (failed.length > 0) {
  console.warn('[Report] Errors:');
  for (const f of failed) {
    console.warn(`  ${f.card}: ${f.error}`);
  }
}

return [{
  json: {
    cardsSucceeded: succeeded.length,
    recordsUpdated: totalUpdated,
    cardsFailed:    failed.length,
    failures: failed.map(f => ({ card: f.card, file: f.file, error: f.error }))
  }
}];
